def combinationSum(self, candidates: list[int], target: int) -> list[list[int]]:
    candidates.sort()
    ans, path = [], []

    def bt(start, remain):
        if remain == 0:
            ans.append(path[:])
            return
        for i in range(start, len(candidates)):
            x = candidates[i]
            if x > remain:
                break
            path.append(x)
            bt(i, remain - x)
            path.pop()

    bt(0, target)
    return ans
